        // 256 bits, bundled since in settle they will be used together
        uint64 kIM;
        uint64 kMM;
        uint128 OI;
        // if takerFee / otcFee is read, hardOICap is also read
        uint128 hardOICap;
        uint64 takerFee;
        uint64 otcFee;
        // 224 bits
        address markRateOracle;
        int16 loUpperConstBase1e4;
        int16 loUpperSlopeBase1e4;
        int16 loLowerConstBase1e4;
        int16 loLowerSlopeBase1e4;
        //
        MarketImpliedRate impliedRate; // 208 bits
        bool useImpliedAsMarkRate;
        //
        mapping(FTag => FIndex) fTagToIndex;
        // not used on hot path
        LiqSettings liqSettings;
        address fIndexOracle;
        // not used on hot path
        string name;
        string symbol;
    }

    struct MarketImmutableDataStruct {
        string name;
        string symbol;
        //
        bool k_isIsolatedOnly; // 8
        uint32 k_maturity; // 32
        TokenId k_tokenId; // 16
        MarketId k_marketId; // 24
        uint8 k_tickStep; // 8
        uint16 k_iTickThresh; // 16
        // Sum = 104
    }

    struct MarketConfigStruct {
        uint16 maxOpenOrders;
        //
        address markRateOracle;
        address fIndexOracle;
        //
        uint128 hardOICap;
        //
        uint64 takerFee;
        uint64 otcFee;
        //
        LiqSettings liqSettings;
        //
        uint64 kIM;
        uint64 kMM;
        uint32 tThresh;
        uint16 maxRateDeviationFactorBase1e4;
        uint16 closingOrderBoundBase1e4;
        //
        int16 loUpperConstBase1e4;
        int16 loUpperSlopeBase1e4;
        int16 loLowerConstBase1e4;
        int16 loLowerSlopeBase1e4;
        //
        MarketStatus status;
        bool useImpliedAsMarkRate;
    }

    // ---------- In-memory state ----------
    struct UserMem {
        MarketAcc addr;
        OrderId[] longIds;
        OrderId[] shortIds;
        FTag fTag;
        int256 preSettleSize;
        int256 postSettleSize;
        int256 signedSize;
        PMDataMem pmData;
    }

    struct MarketMem {
        // write data
        int256 OI;
        int256 origOI;
        // view data
        MarketStatus status;
        uint32 k_maturity;
        uint8 k_tickStep;
        uint256 k_iThresh;
        uint32 tThresh;
        FTag latestFTag;
        uint32 latestFTime;
        uint32 timeToMat;
        int256 rMark;
    }

    // ---------- Market config subtypes ----------

    struct LiqSettings {
        uint64 base;
        uint64 slope;
        uint64 feeRate;
    }

    // ---------- Account related ----------

    struct AccountState {
        AccountData2 data2; // 192 bits
        uint24 delevLiqNonce;
        bool exemptCLOCheck;
        //
        uint64 kIM;
        uint64 kMM;
        uint64 takerDisc;
        uint64 otcDisc;
        //
        StoredOrderIdArr orderIds;
        uint128 sumLongSize;
        uint128 sumLongPM;
        uint128 sumShortSize;
        uint128 sumShortPM;
        PartialData partialData;
    }

    // ---------- Order related ----------
    struct Order {
        OrderStatus status;
        OrderId id;
        MarketAcc maker;
        uint256 size;
        int256 rate;
    }
}

