            z := div(mul(x, ONE), y)
        }
    }

    function divDown(int256 x, int256 y) internal pure returns (int256 z) {
        assembly ("memory-safe") {
            z := mul(x, ONE)
            // Equivalent to `require(y != 0 && ((x * WAD) / WAD == x))`.
            if iszero(mul(y, eq(sdiv(z, ONE), x))) {
                mstore(0x00, 0x5c43740d) // `SDivWadFailed()`.
                revert(0x1c, 0x04)
