    function rawDivCeil(int256 x, int256 d) internal pure returns (int256 z) {
        assembly ("memory-safe") {
            if iszero(d) {
                mstore(0x00, 0x65244e4e) // `DivFailed()`.
                revert(0x1c, 0x04)
