struct DelevResult {
    PayFee winSettle;
    PayFee winPayment;
    PayFee loseSettle;
    PayFee losePayment;
    //
    Trade delevTrade;
}

struct TickInfo {
    // every info are packed here to be read/written all at once
    // see `TickInfoLib.write` and `TickInfoLib.read`
    uint256 packed;
    // Some info that are too big will be stored here.
    // They are expected to not be read/written often.
    uint40 unpackedNumActive;
    uint40 unpackedActiveNonceOffset;
}

struct SweptF {
    FTag fTag;
    Fill __fill;
}

struct PartialData {
    uint128 sumLongSize;
    uint128 sumLongPM;
    uint128 sumShortSize;
    uint128 sumShortPM;
    FTag fTag;
    int128 sumCost;
}

struct PMDataMem {
    uint256 sumLongSize;
