                bestPos = preLen - 1;
            }

            for (uint256 i = preLen; i < len; ++i) {
                OrderId curId = ids[i];
                if (bestId.isZero() || curId < bestId) (bestPos, bestId) = (i, curId);
            }

            (ids[bestPos], ids[len - 1]) = (ids[len - 1], ids[bestPos]);
        }
    }
}

