    IM,
    MM
}

enum GetRequest {
    IM,
    MM,
    ZERO
}

struct BulkOrder {
    MarketId marketId;
    LongShort orders;
    CancelData cancelData;
}

struct BulkOrderResult {
    Trade matched;
    uint256 takerFee;
}

struct LongShort {
    TimeInForce tif;
    Side side;
    uint256[] sizes;
    int16[] limitTicks;
}

struct CancelData {
    OrderId[] ids;
    bool isAll;
    bool isStrict;
}

struct OTCTrade {
    MarketAcc counter;
    Trade trade;
    int256 cashToCounter;
}

struct UserResult {
    PayFee settle;
    PayFee payment;
    //
    OrderId[] removedIds;
    //
    Trade bookMatched;
    MarketAcc partialMaker;
    PayFee partialPayFee;
    //
    bool isStrictIM;
    VMResult finalVM; // finalVM is IM if isStrictIM is true, otherwise it's MM
}

struct OTCResult {
    PayFee settle;
    PayFee payment;
    bool isStrictIM;
    VMResult finalVM; // finalVM is IM if isStrictIM is true, otherwise it's MM
}

struct LiqResult {
    bool isStrictIMLiq;
    VMResult finalVMLiq;
    //
    PayFee liqSettle;
    PayFee liqPayment;
    PayFee vioSettle;
    PayFee vioPayment;
    //
    Trade liqTrade;
}

struct DelevResult {
    PayFee winSettle;
    PayFee winPayment;
    PayFee loseSettle;
    PayFee losePayment;
    //
    Trade delevTrade;
}

struct TickInfo {
    // every info are packed here to be read/written all at once
    // see `TickInfoLib.write` and `TickInfoLib.read`
    uint256 packed;
    // Some info that are too big will be stored here.
    // They are expected to not be read/written often.
    uint40 unpackedNumActive;
    uint40 unpackedActiveNonceOffset;
}

struct SweptF {
    FTag fTag;
    Fill __fill;
}

struct PartialData {
    uint128 sumLongSize;
    uint128 sumLongPM;
    uint128 sumShortSize;
    uint128 sumShortPM;
    FTag fTag;
    int128 sumCost;
}

struct PMDataMem {
    uint256 sumLongSize;
    uint256 sumLongPM;
    uint256 sumShortSize;
    uint256 sumShortPM;
}

type FIndex is bytes26;
type FTag is uint32;
type MatchEvent is uint72;
type TickNonceData is uint256;
type NodeData is uint256;
type PayFee is uint256;
type VMResult is uint256;
type TokenId is uint16;
type MarketId is uint24;
type AMMId is uint24;
type AccountData2 is uint192;

using PayFeeLib for PayFee global;
using TickInfoLib for TickInfo global;
using NodeDataLib for NodeData global;
using MatchEventLib for MatchEvent global;
using TickNonceDataLib for TickNonceData global;
