        MarketImpliedRate self,
        uint32 blockTimestamp,
        int16 newTradedTick,
        uint8 tickStep
    ) internal pure returns (MarketImpliedRate) {
        (uint32 _window, , , int128 currentOracleRate) = self._calcOracleImpliedRate(blockTimestamp, tickStep);
